class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        const int MOD = 1'000'000'007;
        int z = zero, o = one, L = limit;
        int dp[1001][1001][2];
        memset(dp, 0, sizeof(dp));
        for (int i = 0; i <= z; ++i) {
            for (int j = 0; j <= o; ++j) {
                if (i == 0 && j == 0) continue;
                if (i > 0) {
                    int cnt = 0;
                    for (int k = 1; k <= L && k <= i; ++k) {
                        if (j == 0) {
                            if (k == i) cnt = 1;
                        } else {
                            cnt = (cnt + dp[i - k][j][1]) % MOD;
                        }
                    }
                    dp[i][j][0] = cnt;
                }
                if (j > 0) {
                    int cnt = 0;
                    for (int k = 1; k <= L && k <= j; ++k) {
                        if (i == 0) {
                            if (k == j) cnt = 1;
                        } else {
                            cnt = (cnt + dp[i][j - k][0]) % MOD;
                        }
                    }
                    dp[i][j][1] = cnt;
                }
            }
        }
        return (dp[z][o][0] + dp[z][o][1]) % MOD;
    }
};
